"""
MKT Christ Commentary — Isaiah 51 (23 verses — Comfort for Zion / The Cup of Wrath)
Run: python3 scripts/zc-christ-isaiah-51.py
Key decisions:
- v3: Eden restored in Zion — Rev 22:2 (tree of life; Eden-restoration in
  the new Jerusalem); the cosmic garden-restoration that Christ inaugurates
- v4-6: Law/salvation going out to the nations, eternal salvation/righteousness
  — contrasted with temporary heaven and earth; Matt 24:35 / Rev 21:1
- v9-10: Appeal to the divine arm / Rahab slain — the Rahab-sea-monster from
  Genesis-Job mythology; parallel to Rev 12's dragon defeated at the cross
  (Col 2:15); the arm of YHWH in Isa 53:1 = John 12:38
- v11: "The ransomed of the LORD will return" — the homecoming of the redeemed;
  Rev 21:4 (no more tears, mourning, or crying); ultimate fulfillment in new
  Jerusalem
- v17/22: The cup of staggering (kos tarʿelah) — transferred from Jerusalem
  to her oppressors; Matt 26:39 (may this cup pass; Christ drinks the cup
  on behalf of the covenant people); Rev 14:10 / 16:19
"""
import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent


def load_comm(layer, book):
    p = ROOT / "data" / "commentary" / layer / f"{book}.json"
    return json.loads(p.read_text()) if p.exists() else {}


def save_comm(layer, book, data):
    p = ROOT / "data" / "commentary" / layer / f"{book}.json"
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=2))


def merge_comm(existing, new_data):
    # INTENT: Write only absent keys so re-running is safe after manual edits.
    # CHANGE? If isaiah.json schema changes, update merge_comm and ISAIAH dict below.
    # VERIFY: python3 -c "import json; d=json.load(open('data/commentary/mkt-christ/
    #   isaiah.json')); print('Isa 51 v9:',d.get('51',{}).get('9','MISSING')[:80])"
    for ch, verses in new_data.items():
        existing.setdefault(ch, {})
        for v, text in verses.items():
            existing[ch].setdefault(v, text)


ISAIAH = {
    "51": {
        "1": "<p>\"Listen to me, you who pursue righteousness, you who seek the LORD: look to the rock from which you were hewn, and to the quarry from which you were dug\" — the call to those who already seek: \"you who pursue righteousness\" (<em>rōdĕpê ṣedeq</em>) are not the spiritually indifferent but the earnest seekers. They are called to look backward to the rock-origin (Abraham, v2) as the ground of hope. Philippians 3:12-14: \"Not that I have already obtained all this, or have already arrived at my goal, but I press on to take hold of that for which Christ Jesus took hold of me... I press on toward the goal to win the prize for which God has called me heavenward in Christ Jesus.\" The righteousness-pursuers of Isaiah 51:1 are Paul's goal-pressers — and both are called to ground their pursuit not in their own progress but in the initiative of the God who quarried them and called them. Hebrews 12:2: \"fixing our eyes on Jesus, the pioneer and perfecter of faith.\"</p>",
        "2": "<p>\"Look to Abraham your father and to Sarah who bore you; for he was but one when I called him, that I might bless him and multiply him\" — the Abraham-precedent: one man, barren wife, divine call, multiplication. The origin of the covenant people was so improbable that any discouraged remnant can find hope in remembering how few they began. Romans 4:17-21: \"As it is written: 'I have made you a father of many nations.' He is our father in the sight of God, in whom he believed — the God who gives life to the dead and calls into existence the things that do not exist. Against all hope, Abraham in hope believed.\" Galatians 3:16: \"The promises were spoken to Abraham and to his seed... meaning one person, who is Christ.\" The \"one when I called him\" of Isaiah 51:2 is the type of the Son through whom the Abrahamic promise is mediated — Christ is the true Seed, and in him the one-to-many multiplication reaches its ultimate form (Rev 7:9: the innumerable multitude from every nation).</p>",
        "3": "<p>\"For the LORD will comfort Zion; he will comfort all her waste places; he will make her wilderness like Eden, her desert like the garden of the LORD; joy and gladness will be found in her, thanksgiving and the voice of song\" — the Eden-restoration: the wilderness returned to garden. The specific vocabulary — Eden (<em>ʿēden</em>), garden of the LORD (<em>gan-YHWH</em>) — anchors the promise in the creation-narrative. Revelation 22:1-5: the new Jerusalem with the river of life, the tree of life (Ezek 47), \"no longer any night\" — the garden-city that is both Eden-restored and something greater. 2 Corinthians 5:17: \"If anyone is in Christ, the new creation has come.\" John 15:11: \"I have told you this so that my joy may be in you and that your joy may be complete.\" The wilderness-to-Eden of Isaiah 51:3 is the new creation that Christ inaugurates — not yet fully realized in history but tasted in the Spirit (Rom 8:23: firstfruits) and fully actualized in the new Jerusalem.</p>",
        "4": "<p>\"Give attention to me, my people, and give ear to me, my nation; for a law will go out from me, and I will set my justice for a light to the peoples\" — the law (<em>tôrāh</em>) going out from YHWH as light to peoples: the covenant instruction that the Servant carries (42:4: \"the coastlands wait for his law\") here becomes explicit — it will go as light to the nations. Luke 2:32: \"a light for revelation to the Gentiles, and the glory of your people Israel.\" John 1:4-5: \"In him was life, and that life was the light of all mankind. The light shines in the darkness, and the darkness has not overcome it.\" Acts 13:47: \"I have made you a light for the Gentiles, that you may bring salvation to the ends of the earth.\" The law-as-light-to-peoples is fulfilled in Christ, the Light of the world (John 8:12), whose gospel-instruction goes to every nation through the apostolic mission.</p>",
        "5": "<p>\"My righteousness draws near, my salvation has gone out, and my arms will judge the peoples; the coastlands hope for me, and for my arm they wait\" — the divine salvation personified: \"draws near\" and \"gone out\" in parallel, coming from YHWH to the waiting coastlands. Romans 1:16-17: \"For I am not ashamed of the gospel, because it is the power of God that brings salvation to everyone who believes: first to the Jew, then to the Gentile. For in the gospel the righteousness of God is revealed — a righteousness that is by faith from first to last.\" The righteousness that \"draws near\" in Isaiah 51:5 is the righteousness that \"is revealed\" in the gospel — both are the same divine saving-act going out to the waiting nations. The \"arm\" that waits are the arms of Christ on the cross (Isa 53:1) — the divine arm that judges and saves in the same act.</p>",
        "6": "<p>\"Lift up your eyes to the heavens, and look at the earth beneath; for the heavens vanish like smoke, the earth will wear out like a garment, and they who dwell in it will die in like manner; but my salvation will be forever, and my righteousness will never be dismayed\" — the contrast: temporal creation vs. eternal salvation. Heaven and earth will vanish; YHWH's salvation is permanent. Matthew 24:35: \"Heaven and earth will pass away, but my words will never pass away.\" 2 Peter 3:10-13: \"But the day of the Lord will come like a thief. The heavens will disappear with a roar... But in keeping with his promise we are looking forward to a new heaven and a new earth, where righteousness dwells.\" Hebrews 1:11-12: \"They will perish, but you remain; they will all wear out like a garment.\" The eternal salvation of Isaiah 51:6 is the salvation secured by the eternal Son whose \"years will never end\" (Heb 1:12) — the transient creation gives way to the permanent new creation that Christ inaugurates.</p>",
        "7": "<p>\"Listen to me, you who know righteousness, the people in whose heart is my law; fear not the reproach of man, nor be dismayed at their revilings\" — the call to the Torah-hearted community: those who have internalized YHWH's instruction are called to fearlessness before human reproach. Jeremiah 31:33: \"This is the covenant I will make with the people of Israel after that day, declares the LORD. I will put my law in their minds and write it on their hearts.\" Hebrews 12:3: \"Consider him who endured such opposition from sinners, so that you will not grow weary and lose heart.\" 1 Peter 4:14: \"If you are insulted because of the name of Christ, you are blessed, for the Spirit of glory and of God rests on you.\" The community in Isaiah 51:7 whose law is in their hearts and who face reproach is the NT church — the new-covenant people (Jer 31) who face the reproach of human authority in the name of Christ. Fearlessness before reproach is grounded in eternal salvation (v6) rather than temporal approval.</p>",
        "8": "<p>\"For the moth will eat them up like a garment, and the worm will eat them like wool, but my righteousness will be forever, and my salvation to all generations\" — the repeated contrast: the transience of the reproachers (moth-eaten garment) vs. the permanence of YHWH's righteousness. Matthew 6:19-20: \"Do not store up for yourselves treasures on earth, where moths and vermin destroy... But store up for yourselves treasures in heaven, where moths and vermin do not destroy.\" Romans 8:18: \"I consider that our present sufferings are not worth comparing with the glory that will be revealed in us.\" The moth-eaten persecutors of Isaiah 51:8 are the suffering-producing earthly powers that Paul dismisses as incomparable to coming glory — and the \"righteousness to all generations\" is the righteousness that Paul identifies as given to all who are in Christ (Rom 5:17: \"those who receive God's abundant provision of grace and of the gift of righteousness reign in life through the one man, Jesus Christ\").</p>",
        "9": "<p>\"Awake, awake, put on strength, O arm of the LORD; awake, as in days of old, the generations of long ago. Was it not you who cut Rahab in pieces, who pierced the dragon?\" — the appeal to the divine arm: the human plea for YHWH to act as he acted at the Exodus. \"Rahab\" (<em>Raḥab</em>) is the sea-monster / Egypt-as-chaos-dragon of the ancient cosmology (cf. Job 26:12; Ps 89:10). Colossians 2:15: \"And having disarmed the powers and authorities, he made a public spectacle of them, triumphing over them by the cross.\" Revelation 12:9: \"The great dragon was hurled down — that ancient serpent called the devil, or Satan.\" The \"arm of the LORD\" that the community appeals to is identified in John 12:38 and Romans 10:16 as the arm that few believed in — the arm of the Servant of Isaiah 53:1. The dragon-piercing of Isaiah 51:9 finds its ultimate fulfillment at the cross where Christ disarms the cosmic powers and at the parousia where the dragon is permanently bound (Rev 20:2).</p>",
        "10": "<p>\"Was it not you who dried up the sea, the waters of the great deep, who made the depths of the sea a way for the redeemed to pass over?\" — the Exodus sea-crossing remembered: the deep (<em>tĕhôm rabbāh</em>) dried up, the way opened for the redeemed. 1 Corinthians 10:1-2: \"our ancestors were all under the cloud and... all passed through the sea. They were all baptized into Moses in the cloud and in the sea.\" Romans 6:3-4: \"Or don't you know that all of us who were baptized into Christ Jesus were baptized into his death? We were therefore buried with him through baptism into death in order that, just as Christ was raised from the dead through the glory of the Father, we too may live a new life.\" The sea dried up for the redeemed in Isaiah 51:10 is the type of baptism — the waters of death parted so that the redeemed pass through. Christ's death-and-resurrection is the ultimate sea-crossing through which the redeemed pass, buried and raised with him.</p>",
        "11": "<p>\"And the ransomed of the LORD shall return and come to Zion with singing; everlasting joy shall be upon their heads; they shall obtain gladness and joy, and sorrow and sighing shall flee away\" — the great homecoming: <em>pĕdûyê YHWH</em> (ransomed/redeemed of YHWH), joy on their heads, sorrow fled. This verse appears nearly identically in Isaiah 35:10 — the double occurrence frames chapters 36-66. Revelation 21:4: \"'He will wipe every tear from their eyes. There will be no more death' or mourning or crying or pain, for the old order of things has passed away.\" Revelation 7:17: \"the Lamb at the center of the throne will be their shepherd; he will lead them to springs of living water. And God will wipe away every tear from their eyes.\" The ransomed who return with singing in Isaiah 51:11 are the white-robed multitude of Revelation 7 — the redeemed who came out of the great tribulation, led by the Lamb, sorrow permanently banished. The joy is \"everlasting\" (<em>ʿôlam</em>) because the Redeemer who paid for it is eternal.</p>",
        "12": "<p>\"I, I am he who comforts you; who are you that you are afraid of man who dies, of the son of man who is made like grass\" — the double divine \"I\" comfort (<em>ʾānôḵî ʾānôḵî hûʾ mĕnaḥămkem</em>): YHWH the exclusive comforter confronts the fear of mortal humans. John 14:16-17: \"And I will ask the Father, and he will give you another Advocate to help you and be with you forever — the Spirit of truth.\" 1 John 4:18: \"There is no fear in love. But perfect love drives out fear, because fear has to do with punishment. The one who fears is not made perfect in love.\" The fear of mortal man (<em>ʾĕnôš</em>, weak frail humanity) that Isaiah 51:12 confronts is the fear that perfect love drives out in 1 John 4:18 — and the divine Comforter who says \"I, I am He who comforts\" is the Paraclete whom Christ sends (John 14:26: \"the Holy Spirit, whom the Father will send in my name\"). The double-I of v12 is the foundation of NT fearlessness.</p>",
        "13": "<p>\"And have forgotten the LORD, your Maker, who stretched out the heavens and laid the foundations of the earth, and you fear continually all the day because of the wrath of the oppressor, when he sets himself to destroy? And where is the wrath of the oppressor?\" — the diagnosis of fear-driven forgetfulness: preoccupation with the oppressor's wrath crowds out the remembrance of the Creator. Romans 8:15: \"The Spirit you received does not make you slaves, so that you live in fear again; rather, the Spirit you received brought about your adoption to sonship.\" 2 Timothy 1:7: \"For the Spirit God gave us does not make us timid, but gives us power, love and self-discipline.\" The oppressor's wrath that generates constant fear in Isaiah 51:13 is the dominating anxiety from which the Spirit of adoption liberates the believer. The rhetorical question \"where is the wrath of the oppressor?\" is answered by Christ's resurrection: the oppressor whose wrath killed him cannot maintain its grip (Acts 2:24: \"impossible for death to keep its hold on him\").</p>",
        "14": "<p>\"He who is bowed down shall speedily be released; he shall not die and go down to the pit, his bread shall not fail\" — the promise to the captive: quick release, preservation from death, sustained provision. The captive bowed under the oppressor's weight is released; the pit (Sheol) does not claim him. Hebrews 2:14-15: \"Since the children have flesh and blood, he too shared in their humanity so that by his death he might break the power of him who holds the power of death — that is, the devil — and free those who all their lives were held in slavery by their fear of death.\" Christ is the fulfillment of Isaiah 51:14: he goes into the pit (death) so that those who are \"bowed down\" need not go there permanently. The bread that \"shall not fail\" is the bread of life (John 6:35: \"I am the bread of life. Whoever comes to me will never go hungry\") — provision that cannot run out because the provider is risen and eternal.</p>",
        "15": "<p>\"For I am the LORD your God, who stirs up the sea so that its waves roar — the LORD of hosts is his name\" — the divine identity as the sea-stirrer: YHWH who controls the chaos-waters is the one who comforts and releases. Mark 4:39: \"He got up, rebuked the wind and said to the waves, 'Quiet! Be still!' Then the wind died down and it was completely calm.\" Matthew 14:25-27: Jesus walking on water — \"Take courage! It is I.\" (The Greek <em>egō eimi</em> echoes the divine \"I am.\") The disciples' response in Matthew 14:33: \"Truly you are the Son of God.\" The YHWH who stirs up the sea and controls its waves in Isaiah 51:15 is the Jesus who stills the storm — the disciples' recognition in Matthew 14:33 is the NT recognition of Isaiah 51:15's identity. Jesus' sea-sovereignty is a claim to the YHWH-name that the disciples perceive in the boat.</p>",
        "16": "<p>\"And I have put my words in your mouth and covered you in the shadow of my hand, establishing the heavens and laying the foundation of the earth, and saying to Zion, 'You are my people'\" — the Servant's commissioning language (cf. 49:2: \"made my mouth like a sharp sword\"): words placed in the mouth, shadow of the divine hand as protection, creation and covenant in the same breath. John 17:8: \"For I gave them the words you gave me and they accepted them.\" John 17:14: \"I have given them your word.\" Matthew 28:20: \"teaching them to obey everything I have commanded you.\" The words placed in the Servant's mouth in Isaiah 51:16 are the words that the Son gives to his disciples — the Father-to-Son-to-disciples chain of authoritative speech. \"Shadow of my hand\" is the protection that the Father's hand provides to those who carry the Son's words (John 10:29: \"no one can snatch them out of my Father's hand\").</p>",
        "17": "<p>\"Wake yourself, wake yourself, stand up, O Jerusalem, you who have drunk from the hand of the LORD the cup of his wrath, who have drunk to the dregs the cup of staggering\" — the cup of wrath (<em>kôs tarʿēlāh</em>): Jerusalem has drunk the divine anger to the dregs. Matthew 20:22: \"Can you drink the cup I am going to drink?\" Matthew 26:39: \"My Father, if it is possible, may this cup be taken from me. Yet not as I will, but as you will.\" Matthew 26:42: \"My Father, if it is not possible for this cup to be taken away unless I drink it, may your will be done.\" The cup of staggering that Jerusalem drank in the exile is the cup that Christ voluntarily takes at Gethsemane — the full cup of YHWH's wrath against sin. Hebrews 9:28: \"so Christ was sacrificed once to take away the sins of many.\" The drinking-to-the-dregs of Isaiah 51:17 is what Christ undergoes on the cross so that Jerusalem (and all who trust in him) can be commanded to \"wake up\" from the judgment-stupor.</p>",
        "18": "<p>\"There is none to guide her among all the sons she has borne; there is none to take her by the hand among all the sons she has brought up\" — the abandoned city: no guide, no hand to take. All the sons Jerusalem bore cannot help her. The utter loneliness of judgment — even the generations produced by the covenant community cannot reverse the divine sentence. Isaiah 41:10: \"I will strengthen you and help you; I will uphold you with my righteous right hand.\" Luke 15:20: \"While he was still a long way off, his father saw him and was filled with compassion for him; he ran to his son, threw his arms around him and kissed him.\" The sons who cannot guide Jerusalem in Isaiah 51:18 are the older brother who will not welcome the returning prodigal — and the Father who runs to meet the one returning is the YHWH who takes Jerusalem by the hand when all human guides have failed. Christ is the one who takes by the hand those whom human helpers cannot reach (Mark 9:27: \"Jesus took him by the hand and lifted him to his feet\").</p>",
        "19": "<p>\"These two things have come upon you — who will console you? — devastation and destruction, famine and sword; who will comfort you?\" — the fourfold disaster: devastation, destruction, famine, sword. The repetition of the comfort-question emphasizes the apparent impossibility of comfort after such total loss. John 16:20-22: \"Very truly I tell you, you will weep and mourn while the world rejoices. You will grieve, but your grief will turn to joy. A woman giving birth to a child has pain because her time has come; but when her baby is born she forgets the anguish because of her joy that a child is born into the world. So with you: Now is your time of grief, but I will see you again and you will rejoice, and no one will take away your joy.\" The impossible-to-comfort grief of Isaiah 51:19 is what Jesus addresses in the upper room — the disciples' grief will turn to joy that no one can take (John 16:22). The comforter who can meet the level of devastation in Isaiah 51:19 is the divine Comforter (John 14:16).</p>",
        "20": "<p>\"Your sons have fainted; they lie at the head of every street like an antelope in a net; they are full of the wrath of the LORD, the rebuke of your God\" — the images of defeat: sons fallen at the crossroads, caught like animals in a net, filled with divine wrath. The net (<em>mikmār</em>) is the trap; the antelope has no escape. Luke 21:34-36: \"Be careful, or your hearts will be weighed down with carousing, drunkenness and the anxieties of life, and that day will close on you suddenly like a trap. For it will come on all those who live on the face of the whole earth. Be always on the watch, and pray that you may be able to escape all that is about to happen, and that you may be able to stand before the Son of Man.\" The net that traps the antelope in Isaiah 51:20 is the trap that the day of the Lord will spring — and Christ's call to watchful prayer is the escape from the trap that human sons caught in Isaiah 51:20 cannot find on their own.</p>",
        "21": "<p>\"Therefore hear this, you who are afflicted, who are drunk, but not with wine\" — the address to the staggering-not-from-wine: the cup of divine wrath produces a stupor that is not alcoholic but spiritual. Isaiah 29:9 described the same stupor as judgment. Romans 11:7-8: \"What the people of Israel sought so earnestly they did not obtain. The elect among them did, but the others were hardened, as it is written: 'God gave them a spirit of stupor, eyes that could not see and ears that could not hear, to this day.'\" The spiritual stupor of Isaiah 51:21 — drunk not with wine but with YHWH's judgment — is the hardening Paul describes in Romans 11. The reversal comes when Israel receives mercy through the fullness of the Gentiles (Rom 11:25-26: \"all Israel will be saved\"). The awakening from the stupor in Isaiah 51:17's \"wake yourself\" is the awakening that comes through Christ's mercy.</p>",
        "22": "<p>\"Thus says your Lord, the LORD, your God who pleads the cause of his people: 'Behold, I have taken from your hand the cup of staggering; the bowl of my wrath you shall drink no more'\" — the cup removed: YHWH takes back the cup of staggering from Jerusalem's hand. The transfer is total: no more wrath-drinking for the covenant city. Revelation 14:10: \"They, too, will drink the wine of God's fury, which has been poured full strength into the cup of his wrath.\" Revelation 16:19: \"God remembered Babylon the Great and gave her the cup filled with the wine of the fury of his wrath.\" The cup that is removed from Jerusalem (Is 51:22) is given to Babylon/the oppressor (v23) — and in the NT, the cup of divine wrath ultimately falls on Christ at the cross (Matthew 26:39) and on unrepentant humanity at the final judgment (Rev 14:10). The removal of the cup from Jerusalem is the removal that the cross accomplishes: Christ drinks what the covenant people could not survive.</p>",
        "23": "<p>\"And I will put it into the hand of your tormentors, who have said to you, 'Bow down, that we may pass over'; and you have made your back like the ground and like the street for them to pass over\" — the transfer: the cup moves from Jerusalem to her oppressors. The humiliation (\"bow down, that we may pass over\" — prostration as a stepping-stone) is reversed. Revelation 3:9: \"I will make those who are of the synagogue of Satan... come and fall down at your feet and acknowledge that I have loved you.\" Philippians 2:9-11: \"at the name of Jesus every knee should bow... and every tongue acknowledge that Jesus Christ is Lord.\" The reversal of the stepping-stone humiliation in Isaiah 51:23 is the reversal enacted at Christ's exaltation: those who trampled the despised servant find that the servant is exalted to the highest place, and every knee must bow to the name once used as a stepping-stone. The tormentors who receive the cup are ultimately judged by the one they tormented (Rev 6:10-11).</p>"
    }
}


def main():
    existing = load_comm("mkt-christ", "isaiah")
    before = sum(len(v) for v in existing.values())
    merge_comm(existing, ISAIAH)
    after = sum(len(v) for v in existing.values())
    save_comm("mkt-christ", "isaiah", existing)
    print(f"{len(existing)} chapters, {after} verse entries total (+{after - before} new)")
    for v, kw in [("9", "dragon"), ("11", "ransomed"), ("17", "cup"), ("22", "staggering")]:
        entry = existing.get("51", {}).get(v, "MISSING")
        print(f"  Isa 51:{v} — {'OK' if kw.lower() in entry.lower() else 'CHECK'}")
    ch = existing.get("51", {})
    missing = [str(i) for i in range(1, 24) if str(i) not in ch]
    print(f"  Missing verses: {missing if missing else 'none'}")


if __name__ == "__main__":
    main()
